local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)
---@class LFDTUnitView
local LFDTUnitView = LxClass("LFDTUnitView")

function LFDTUnitView:LFDTUnitView()
    ---@type LFDTManager
    self._mgr = nil

    ---@type LFastDreamTripMap
    self._map = nil

    ---@type Transform
    self._gridTrans = nil

    self._iconTemplateRoot = nil

    ---@type LDisplaySpine
    self._spineDp = nil

    ---@type LDisplayEffect
    self._effectDp = nil

    ---@type table<string,LDisplayEffect>
    self._effectDpMap = nil

    ---@type table<string,LDisplayEffect>
    self._effectDpOtherMap = nil

    ---@type Transform
    self._iconDp = nil

    ---@type Transform 标记
    self._targetIconDp = nil

    ---@type LFDTUnitData
    self._unitData = nil

    ---@type number 当前位置
    self._unitIndex = 0

    ---@type boolean
    self._hasTargetUnit = false

    ---@type table<string,LFDTUnitData>
    self._targetUnitDataMap = nil

    ---@type boolean
    self._hasOtherTargetUnit = false

    ---@type table<string,LFDTUnitData>
    self._otherTargetUnitDataMap = nil


    --- LFastDTResConst
    self._resType = nil

    self._loadFinishNum = 0
    self._loadAllNum = 0

    ---@type function 加载回调
    self._loadCb = nil

    self._isDisposed = false
end

function LFDTUnitView:Dispose()
    if self:IsDisposed() then return end

    self:DestroyShow()

    table.remove(self)
    self._isDisposed = true
end

function LFDTUnitView:IsDisposed()
    return self._isDisposed
end

function LFDTUnitView:SetIconTemp(iconTemplateRoot)
    self._iconTemplateRoot = iconTemplateRoot
end

---@param mgr LFDTManager
---@param unitData LFDTUnitData
---@param gridTrans Transform
function LFDTUnitView:SetData(mgr,unitData,gridTrans,loadCb)
    self._mgr = mgr
    self._map = mgr:GetMap()
    self._gridTrans = gridTrans
    self._resType = unitData:GetResType()
    self._unitData = unitData
    self._loadCb = loadCb

    if unitData:IsNPCUnit() then
        self._unitIndex = unitData:GetUnitViewIndex()
    else
        self._unitIndex = gModelFastDreamTrip:GetDreamTripIndex()
    end
end

--- 加载 Spine start
function LFDTUnitView:InitSpineDp(resName)
    if not self._unitData then return end

    ---@type LFDTUnitData
    local unitData = self._unitData
    local posZ = unitData:GetResPosZ()

    if self._spineDp then
        self._spineDp:Destroy()
    end

    ---@type LDisplaySpine
    local spine = LDisplaySpine:New()
    self._spineDp = spine
    local spineType = LDisplaySpine.TYPE_MODEL
    spine:CreateSpine(self._gridTrans, resName,spineType)
    spine:SetRenderOrder(posZ)
    spine:SetLoadedFunction(function()
        local targetLoadNum = 0
        if self._hasTargetUnit then
            for k,v in pairs(self._targetUnitDataMap) do
                targetLoadNum = targetLoadNum + 1
            end
            self:LoadTargetUnit()
        end
        self._loadAllNum = self._loadAllNum + targetLoadNum
        self:OnSpineLoaded()
        print(spine:GetRenderLayer())
    end)
    spine:StartLoad()
end

function LFDTUnitView:OnSpineLoaded()
    self:DoLoadCb()
end
--- 加载 Spine end



--- 加载 effect start
function LFDTUnitView:InitEffectDp(resName)
    if not self._unitData then return end

    ---@type LFDTUnitData
    local unitData = self._unitData
    local posZ = unitData:GetResPosZ()

    if self._effectDp then
        self._effectDp:Destroy()
    end

    ---@type LDisplayEffect
    local effectDp = LDisplayEffect:New()
    self._effectDp = effectDp
    effectDp:CreateEffect(self._gridTrans, resName)
    effectDp:SetRenderOrder(posZ)
    effectDp:SetLoadedFunction(function(eff)
        self:OnEffectLoaded()
    end)
    effectDp:StartLoadEffect()
end

function LFDTUnitView:OnEffectLoaded()
    self:DoLoadCb()
end
--- 加载 effect end


--- 加载 icon start
function LFDTUnitView:InitIconDp(resName)
    local unitData = self._unitData
    local itemNew = LxResUtil.NewObject(self._iconTemplateRoot)
    self._iconDp = itemNew
    itemNew.name = "icon_" .. unitData:GetKey()

    local iconTrans = itemNew.transform
    iconTrans:SetParent(self._gridTrans,false)
    self._map:SetSprite(iconTrans,resName,nil)

    local spriteRender = iconTrans:GetComponent(typeSpriteRenderer)
    spriteRender.sortingOrder = unitData:GetResPosZ()

    CS.ShowObject(iconTrans,true)
    self:OnIconLoaded(itemNew,resName)
end

function LFDTUnitView:OnIconLoaded(iconObj)
    self:DoLoadCb()
end
--- 加载 icon end

function LFDTUnitView:Load()
    self._loadFinishNum = 0
    self._loadAllNum = 1

    ---@type LFDTUnitData
    local unitData = self._unitData
    if unitData and not unitData:CheckUnitShowState() then
        self:DoLoadCb()
        return
    end

    local resType = self._resType
    local resName = unitData:GetResName()
    if string.isempty(resName) then
        self:DoLoadCb()
        return
    end
    if resType == LFastDTResConst.PIC then
        self:InitIconDp(resName)
    elseif resType == LFastDTResConst.SPINE then
        self:InitSpineDp(resName)
    elseif resType == LFastDTResConst.EFFECT then
        self:InitEffectDp(resName)
    elseif resType == LFastDTResConst.PICEFFECT then
        local resInfos = string.split(resName,";")
        self._loadAllNum = #resInfos
        if resInfos[1] then
            self:InitIconDp(resInfos[1])
        end
        if resInfos[2] then
            self:InitEffectDp(resInfos[2])
        end
    end
end

function LFDTUnitView:LoadTargetUnit()
    if not self._hasTargetUnit then return end
    if not self._effectDpMap then
        self._effectDpMap = {}
    end
    local resType
    ---@param v LFDTUnitData
    for k,v in pairs(self._targetUnitDataMap) do
        resType = v:GetResType()
        if resType == LFastDTResConst.EFFECT then
            self:InitTargetEffect(v)
        end
    end
end

---@param unitData LFDTUnitData
function LFDTUnitView:InitTargetEffect(unitData)
    if not self._spineDp then return end
    if not unitData then return end

    local posZ = unitData:GetResPosZ()

    if not self._effectDpMap then
        self._effectDpMap = {}
    end

    ---@type LDisplayEffect
    local effectDp = LDisplayEffect:New()
    self._effectDpMap[unitData:GetKey()] = effectDp
    local spTrans = self._spineDp:GetSpineTrans()
    effectDp:CreateEffect(spTrans, unitData:GetResName())
    effectDp:SetRenderOrder(posZ)
    ---@param eff LDisplayEffect
    effectDp:SetLoadedFunction(function(eff)
        local trans = eff:GetDisplayTrans()
        trans.position = unitData:GetResPos()
        eff:SetVisible(false)
        self:DoFinishLoadCb()
    end)
    effectDp:StartLoadEffect()
end

function LFDTUnitView:DoLoadCb()
    self:SetUnitTransScale()
    self:DoFinishLoadCb()
end

function LFDTUnitView:DoFinishLoadCb()
    self._loadFinishNum = self._loadFinishNum + 1
    if self._loadFinishNum >= self._loadAllNum then
        local loadCb = self._loadCb
        self._loadCb = nil
        if loadCb then
            loadCb()
        end
    end
end

