function LFDTUnitView:DestroyShow()
    if self._spineDp then
        self._spineDp:Destroy()
        self._spineDp = nil
    end
    if self._effectDp then
        self._effectDp:Destroy()
        self._effectDp = nil
    end
    if self._effectDpMap then
        for k,v in pairs(self._effectDpMap) do
            v:Destroy()
        end
        self._effectDpMap = nil
    end
    if self._effectDpOtherMap then
        for k,v in pairs(self._effectDpOtherMap) do
            v:Destroy()
        end
        self._effectDpOtherMap = nil
    end
    if self._iconDp then
        LxResUtil.DestroyObject(self._iconDp.gameObject)
        self._iconDp = nil
    end
    if self._targetIconDp then
        LxResUtil.DestroyObject(self._targetIconDp.gameObject)
        self._targetIconDp = nil
    end
end

function LFDTUnitView:SetTargetInfo(targetUnitDataMap)
    if not targetUnitDataMap then return end
    self._hasTargetUnit = true
    self._targetUnitDataMap = targetUnitDataMap
end

function LFDTUnitView:SetOtherTargetInfo(otherTargetUnitDataMap)
    if not otherTargetUnitDataMap then return end
    self._hasOtherTargetUnit = true
    self._otherTargetUnitDataMap = otherTargetUnitDataMap
end

function LFDTUnitView:GetGridTrans()
    return self._gridTrans
end

---@return LFDTUnitData
function LFDTUnitView:GetUnitData()
    return self._unitData
end

function LFDTUnitView:GetUnitTrans()
    if self._spineDp then
        return self._spineDp:GetSpineTrans()
    end
    if self._effectDp then
        return self._effectDp:GetDisplayTrans()
    end
    return self._iconDp
end

function LFDTUnitView:GetUnitSpineDp()
    return self._spineDp
end

function LFDTUnitView:SetUnitTransVisiable(bShow)
    local trans = self:GetUnitTrans()
    if not trans then return end
    if bShow and self._unitData then
        bShow = self:CheckUnitShowState()
    end
    CS.ShowObject(trans,bShow)
end

function LFDTUnitView:CheckUnitShowState()
    return self._unitData and self._unitData:CheckUnitShowState()
end

function LFDTUnitView:SetUnitTransScale()
    if not self._unitData then return end

    local trans = self:GetUnitTrans()
    if not trans then return end

    local showState = self:CheckUnitShowState()
    if showState then
        trans.localScale = self._unitData:GerResSizeVec3()
        self._unitData:GetShowPos(trans)
    end
    CS.ShowObject(trans,showState)
end

---@return StructDreamTripEventInfo
function LFDTUnitView:GetCurEventInfo()
    return self:GetUnitData():GetCurEventInfo()
end

function LFDTUnitView:SetPlayerAni(ani,isLoop)
    if not self._spineDp then return end
    self._spineDp:PlayAnimationSolid(ani,isLoop,false)
end

function LFDTUnitView:SetSpineFilp(bFilp)
    if not self._spineDp then  return end
    self._spineDp:SetFlipX(bFilp)
end

function LFDTUnitView:CheckIsNPCUnit()
    if not self._unitData then return false end
    return self._unitData:IsNPCUnit()
end

function LFDTUnitView:UpdateUnitData(config)
    if not self:CheckIsNPCUnit() then return end
    self._unitData:UpdateGridData()

    local trans = self:GetUnitTrans()
    if not trans then return end

    config = config or {}
    local hasAutoGet = config.hasAutoGet
    if hasAutoGet then return end

    local showState = self:CheckUnitShowState()
    CS.ShowObject(trans,showState)
end

function LFDTUnitView:SetUnitViewIndex(unitIndex)
    self._unitIndex = unitIndex
end

function LFDTUnitView:GetUnitViewIndex()
    return self._unitIndex
end

function LFDTUnitView:SetTargetShow(showKey)
    if not self._hasTargetUnit then return end
    if not self._effectDpMap then return end
    ---@param v LFDTUnitData
    for k,v in pairs(self._targetUnitDataMap) do
        local effKey = v:GetKey()
        local show = false
        if showKey and showKey == effKey then
            show = true
        end
        ---@type LDisplayEffect
        local effectDp = self._effectDpMap[effKey]
        if effectDp then
            effectDp:SetVisible(show)
        end
    end
end

function LFDTUnitView:SetOtherTargetShow(showKey)
   if not self._hasOtherTargetUnit then return end
    if not self._effectDpMap then return end
    ---@param v LFDTUnitData
    for k,v in pairs(self._otherTargetUnitDataMap) do
        local effKey = v:GetKey()
        local show = false
        if showKey and showKey == effKey then
            show = true
        end
        ---@type LDisplayEffect
        local effectDp = self._effectDpMap[effKey]
        if effectDp then
            effectDp:SetVisible(show)
        end
    end
end

function LFDTUnitView:SetBattleTargetShow(bShow)
    if not self._hasTargetUnit then return end

    if not self._effectDpMap then return end

    local showKey = "battleEff"
    ---@type LFDTUnitData
    local targetUnitData = self._targetUnitDataMap[showKey]
    if not targetUnitData then return end

    ---@type LDisplayEffect
    local effectDp = self._effectDpMap[targetUnitData:GetKey()]
    if effectDp then
        effectDp:SetVisible(bShow)
    end
end

function LFDTUnitView:SetUnitOtherEffectShow(effName,bShow,state)
    if string.isempty(effName) then return end
    if not self._effectDpOtherMap then
        self._effectDpOtherMap = {}
    end
    ---@type LDisplayEffect
    local effectDp = self._effectDpOtherMap[effName]
    if not effectDp then
        effectDp = LDisplayEffect:New()
        self._effectDpOtherMap[effName] = effectDp
        local spTrans = self._spineDp:GetSpineTrans()
        effectDp:CreateEffect(spTrans, effName)
        effectDp:SetRenderOrder(0)
        ---@param eff LDisplayEffect
        effectDp:SetLoadedFunction(function(eff)
            eff:SetVisible(bShow)
        end)
        effectDp:StartLoadEffect()
    else
        effectDp:SetVisible(bShow)
    end
end

function LFDTUnitView:SetUnitOtherEffectDpShow(effName,bShow)
    if string.isempty(effName) then return end
    if not self._effectDpOtherMap then
        self._effectDpOtherMap = {}
    end
    ---@type LDisplayEffect
    local effectDp = self._effectDpOtherMap[effName]
    if not effectDp then return end
    effectDp:SetVisible(bShow)
end

return LFDTUnitView